<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">chrome</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --use-fake-device-for-media-stream</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
